        <div class="elementor-element elementor-element-98b885b elementor-widget elementor-widget-gallery" data-id="98b885b" data-element_type="widget" data-settings="{&quot;columns&quot;:1,&quot;gap&quot;:{&quot;unit&quot;:&quot;px&quot;,&quot;size&quot;:5,&quot;sizes&quot;:[]},&quot;aspect_ratio&quot;:&quot;16:9&quot;,&quot;overlay_title&quot;:&quot;title&quot;,&quot;lazyload&quot;:&quot;yes&quot;,&quot;gallery_layout&quot;:&quot;grid&quot;,&quot;columns_tablet&quot;:2,&quot;columns_mobile&quot;:1,&quot;gap_tablet&quot;:{&quot;unit&quot;:&quot;px&quot;,&quot;size&quot;:10,&quot;sizes&quot;:[]},&quot;gap_mobile&quot;:{&quot;unit&quot;:&quot;px&quot;,&quot;size&quot;:10,&quot;sizes&quot;:[]},&quot;link_to&quot;:&quot;file&quot;,&quot;overlay_background&quot;:&quot;yes&quot;,&quot;content_hover_animation&quot;:&quot;fade-in&quot;}" data-widget_type="gallery.default">
            <div class="elementor-widget-container">
                <div class="elementor-gallery__container e-gallery-container e-gallery-grid e-gallery--ltr e-gallery--lazyload" style="--hgap: 5px; --vgap: 5px; --animation-duration: 350ms; --columns: 1; --rows: 1; --aspect-ratio: 56.25%; --container-aspect-ratio: 56.25%;">
                    <a class="e-gallery-item elementor-gallery-item elementor-animated-content" href="https://melsu.ru/media/2024/03/tgatu-14-1024x618-1.jpg" data-elementor-open-lightbox="no" data-featherlight="image" style="--column: 0; --row: 0;">
                        <div class="e-gallery-image elementor-gallery-item__image e-gallery-image-loaded" data-thumbnail="https://melsu.ru/media/2024/03/tgatu-14-1024x618-1.jpg" data-width="1024" data-height="618" aria-label="" role="img" style="background-image: url(&quot;https://melsu.ru/media/2024/03/tgatu-14-1024x618-1.jpg&quot;);"></div>
                        <div class="elementor-gallery-item__overlay"></div>
