                    <a class="e-gallery-item elementor-gallery-item elementor-animated-content" href="https://melsu.ru/media/2024/03/photo_2023-11-03_18-44-19-1024x682-1.jpg" data-elementor-open-lightbox="no" data-featherlight="image" style="--column: 2; --row: 0;">
                        <div class="e-gallery-image elementor-gallery-item__image e-gallery-image-loaded" data-thumbnail="https://melsu.ru/media/2024/03/photo_2023-11-03_18-44-19-1024x682-1.jpg" data-width="1024" data-height="682" aria-label="" role="img" style="background-image: url(&quot;https://melsu.ru/media/2024/03/photo_2023-11-03_18-44-19-1024x682-1.jpg&quot;);"></div>
